// Bitter (SIL Open Font License, siehe OFL.txt), Latin-Subset von Google Fonts.
//
// Warum Base64 statt einer .ttf-Datei: pdf-lib kann nur TTF/OTF einbetten (das WOFF2 aus
// @fontsource erzeugt ein kaputtes PDF), und Vite kopiert Server-Assets nicht in die
// Build-Ausgabe. Als TS-Modul landet die Schrift zuverlässig im Bundle.
//
// Aus den TTFs wurden die Tabellen GSUB, GDEF und STAT entfernt: fontkit wendet sonst
// Ligaturen/kontextuelle Alternativen an, deren Glyphen pdf-lib falsch platziert
// ("fotografiere" wurde zu "fotograf iere" mit Lücke, Textkopie ergab "fotogra~iere").

const BITTER_REGULAR_BASE64 =
	'';

const BITTER_BOLD_BASE64 =
	'';

export const BITTER_REGULAR_BYTES = Buffer.from(BITTER_REGULAR_BASE64, 'base64');
export const BITTER_BOLD_BYTES = Buffer.from(BITTER_BOLD_BASE64, 'base64');
